mapper.select:
SELECT id, stage_id, paper, title, prompt_text, exam_year, image_url, material_text, source, is_active, created_at, updated_at
FROM essay_prompt
WHERE stage_id = #{stageId}
  AND is_active = 1

      AND exam_year = #{examYear}


      AND (
          paper LIKE CONCAT('%', #{keyword}, '%')
          OR title LIKE CONCAT('%', #{keyword}, '%')
          OR prompt_text LIKE CONCAT('%', #{keyword}, '%')
      )

ORDER BY paper DESC

    LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM essay_prompt
WHERE stage_id = #{stageId}
  AND is_active = 1

      AND exam_year = #{examYear}


      AND (
          paper LIKE CONCAT('%', #{keyword}, '%')
          OR title LIKE CONCAT('%', #{keyword}, '%')
          OR prompt_text LIKE CONCAT('%', #{keyword}, '%')
      )
